# ❌ ANTI-PATTERN: Reloading model on every prediction
class PoorBowler:
    def predict_match_situation(self, commentary):
        # Model loaded fresh every call—catastrophic memory waste
        model = AutoModelForSequenceClassification.from_pretrained('bert-base')
        tokenizer = AutoTokenizer.from_pretrained('bert-base')
        inputs = tokenizer(commentary, return_tensors='pt')
        return model(**inputs)

# ✅ BEST PRACTICE: Lazy loading with caching
class OptimizedBowler:
    _model_cache = {}
    _tokenizer_cache = {}

    @classmethod
    def get_model(cls, model_name='bert-base'):
        if model_name not in cls._model_cache:
            cls._model_cache[model_name] = (
                AutoModelForSequenceClassification.from_pretrained(model_name)
                .eval().to('cuda' if torch.cuda.is_available() else 'cpu')
            )
        return cls._model_cache[model_name]

    @classmethod
    def get_tokenizer(cls, model_name='bert-base'):
        if model_name not in cls._tokenizer_cache:
            cls._tokenizer_cache[model_name] = AutoTokenizer.from_pretrained(model_name)
        return cls._tokenizer_cache[model_name]

    def predict_match_situation(self, commentaries, batch_size=32):
        model = self.get_model()
        tokenizer = self.get_tokenizer()

        # Dynamic padding: pad only within batch, not globally
        all_logits = []
        for i in range(0, len(commentaries), batch_size):
            batch = commentaries[i:i+batch_size]
            inputs = tokenizer(
                batch, 
                return_tensors='pt', 
                padding='longest',  # Pad to longest in THIS batch
                truncation=True,
                max_length=128
            ).to(model.device)

            with torch.no_grad():
                outputs = model(**inputs)
                all_logits.append(outputs.logits.cpu())

        return torch.cat(all_logits, dim=0)

bowler = OptimizedBowler()
# First call: loads model once
situation_scores_1 = bowler.predict_match_situation(['aggressive batting line', 'defensive field setup'])
# Second call: reuses cached model—50x faster
situation_scores_2 = bowler.predict_match_situation(['spinner attacking'])
